def normalize_total(total):
    if isinstance(total, dict):
        return total.get("value", 0)
    if isinstance(total, int):
        return total
    return 0

@app.get("/api/search")
def search_products():
    keyword = (request.args.get("q") or "").strip()
    if not keyword:
        return jsonify({"error": "Missing required query parameter: q"}), 400

    page, size, offset = parse_pagination()
    cache_key = f"{keyword.lower()}|{page}|{size}"

    cached = cache.get(cache_key)
    if cached is not None:
        response = jsonify(cached)
        response.headers["Cache-Control"] = "public, max-age=15"
        response.headers["X-Cache"] = "HIT"
        return response

    body = build_search_query(keyword, offset, size)

    try:
        result = es.search(index=ELASTICSEARCH_INDEX, body=body)
        hits = result.get("hits", {})
        items = []
        for hit in hits.get("hits", []):
            source = hit.get("_source", {}) or {}
            source["_id"] = hit.get("_id")
            source["_score"] = hit.get("_score")
            items.append(source)

        payload = {
            "query": keyword,
            "page": page,
            "size": size,
            "total": normalize_total(hits.get("total")),
            "products": items,
        }
        cache.set(cache_key, payload)

        response = jsonify(payload)
        response.headers["Cache-Control"] = "public, max-age=15"
        response.headers["X-Cache"] = "MISS"
        return response

    except ESConnectionError:
        return jsonify({"error": "Search service unavailable"}), 503
    except TransportError as e:
        status_code = 500
        if hasattr(e, "status_code") and isinstance(e.status_code, int):
            if 400 <= e.status_code <= 599:
                status_code = e.status_code
        return jsonify({"error": "Search request failed"}), status_code
    except Exception:
        return jsonify({"error": "Internal server error"}), 500

